#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    struct Node *left, *right;
} Node;

Node* newNode() {
    Node* n = (Node*)malloc(sizeof(Node));
    n->left = n->right = NULL;
    return n;
}

int isMirror(Node* a, Node* b) {
    if (!a && !b) return 1;
    if (!a || !b) return 0;
    return isMirror(a->left, b->right) && isMirror(a->right, b->left);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // node ids are ≤100000, allocate static array
        static Node* nodes[100001];
        static int isChild[100001];
        // reset only needed positions
        for (int i = 0; i <= 100000; ++i) { nodes[i] = NULL; isChild[i] = 0; }
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (!nodes[p]) nodes[p] = newNode();
            if (!nodes[c]) nodes[c] = newNode();
            if (dir == 'L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
            isChild[c] = 1;
        }
        // find root (the one that never appeared as child)
        int rootId = -1;
        for (int i = 0; i <= 100000; ++i) {
            if (nodes[i] && !isChild[i]) { rootId = i; break; }
        }
        Node* root = (rootId==-1)? NULL : nodes[rootId];
        if (!root || isMirror(root->left, root->right))
            printf("YES\n");
        else
            printf("NO\n");
        // free memory (optional for contest)
        for (int i = 0; i <= 100000; ++i) if (nodes[i]) free(nodes[i]);
    }
    return 0;
}

