struct Node {
    Node *left = nullptr, *right = nullptr;
};

bool isMirror(Node* a, Node* b) {
    if (!a && !b) return true;
    if (!a || !b) return false;
    return isMirror(a->left, b->right) && isMirror(a->right, b->left);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        unordered_map<int, Node*> mp;
        unordered_set<int> childSet;
        for (int i=0;i<N-1;++i) {
            int p,c; char dir; cin>>p>>c>>dir;
            if (!mp.count(p)) mp[p]=new Node();
            if (!mp.count(c)) mp[c]=new Node();
            if (dir=='L') mp[p]->left = mp[c];
            else mp[p]->right = mp[c];
            childSet.insert(c);
        }
        int rootId = -1;
        for (auto &kv: mp) if (!childSet.count(kv.first)) { rootId = kv.first; break; }
        Node* root = (rootId==-1)? nullptr : mp[rootId];
        if (!root || isMirror(root->left, root->right)) cout << "YES\n";
        else cout << "NO\n";
        // optional cleanup
        for (auto &kv: mp) delete kv.second;
    }
    return 0;
}

