import java.io.*;
import java.util.*;

class Main {
    static class Node {
        Node left, right;
        Node() { left = right = null; }
    }

    static boolean isMirror(Node a, Node b) {
        if (a == null && b == null) return true;
        if (a == null || b == null) return false;
        return isMirror(a.left, b.right) && isMirror(a.right, b.left);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> child = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                map.putIfAbsent(p, new Node());
                map.putIfAbsent(c, new Node());
                if (dir == 'L') map.get(p).left = map.get(c);
                else map.get(p).right = map.get(c);
                child.add(c);
            }
            int rootId = -1;
            for (int id : map.keySet()) if (!child.contains(id)) { rootId = id; break; }
            Node root = (rootId == -1) ? null : map.get(rootId);
            if (root == null || isMirror(root.left, root.right)) out.append("YES\n");
            else out.append("NO\n");
        }
        System.out.print(out.toString());
    }
}

