import sys

def is_mirror(a, b):
    if not a and not b:
        return True
    if not a or not b:
        return False
    return is_mirror(a[0], b[1]) and is_mirror(a[1], b[0])

# Node will be stored as a tuple (left, right) where each element is either None or another tuple

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nodes = {}
        child_set = set()
        for __ in range(N-1):
            p = int(next(it)); c = int(next(it)); dir = next(it)
            if p not in nodes:
                nodes[p] = [None, None]  # [left, right]
            if c not in nodes:
                nodes[c] = [None, None]
            if dir == 'L':
                nodes[p][0] = nodes[c]
            else:
                nodes[p][1] = nodes[c]
            child_set.add(c)
        root_id = None
        for nid in nodes:
            if nid not in child_set:
                root_id = nid
                break
        root = None if root_id is None else nodes[root_id]
        if root is None or is_mirror(root[0], root[1]):
            out_lines.append('YES')
        else:
            out_lines.append('NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

